fn solve(nums: Vec<i64>) -> i64 {
    let max_index = nums.len() - 1;
    if max_index == 0 {
        return nums[0].abs();
    }
    let mut sieve = vec![true; max_index + 1];
    sieve[0] = false;
    if max_index >= 1 {
        sieve[1] = false;
    }
    for i in 2..=max_index {
        if sieve[i] {
            let mut j = i * 2;
            while j <= max_index {
                sieve[j] = false;
                j += i;
            }
        }
