    let mut sum_a = 0;
    let mut sum_b = 0;
    for (i, &num) in nums.iter().enumerate() {
        if sieve[i] {
            sum_a += num;
        } else {
            sum_b += num;
        }
    }
    (sum_a - sum_b).abs()
}
